const response = items[0].json;
const topic = $node['Claim Next Pending Topic'].json[0];
const topicId = topic.id;
const topicText = topic.topic;

// Extract the generated text
const articleContent = response.choices?.[0]?.message?.content || '';

// Parse title from first # heading or use topic
const titleMatch = articleContent.match(/^#\s+(.+)$/m);
const articleTitle = titleMatch ? titleMatch[1].trim() : topicText;

// Build HTML email version
const htmlContent = articleContent
  .replace(/^# (.+)$/gm, '<h1>$1</h1>')
  .replace(/^## (.+)$/gm, '<h2>$1</h2>')
  .replace(/^### (.+)$/gm, '<h3>$1</h3>')
  .replace(/^\*\*(.+?)\*\*/gm, '<strong>$1</strong>')
  .replace(/^\*(.+?)\*/gm, '<em>$1</em>')
  .replace(/```([\s\S]*?)```/g, '<pre><code>$1</code></pre>')
  .replace(/`([^`]+)`/g, '<code>$1</code>')
  .replace(/\n\n/g, '</p><p>')
  .replace(/^(.+)$/gm, (line) => {
    if (line.startsWith('<h') || line.startsWith('<pre') || line.startsWith('<ul') || line.trim() === '') return line;
    return line;
  });

const emailHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <style>
    body { font-family: Georgia, serif; max-width: 800px; margin: 40px auto; color: #333; line-height: 1.7; }
    h1 { color: #1a1a1a; font-size: 2em; border-bottom: 2px solid #333; padding-bottom: 10px; }
    h2 { color: #2c2c2c; font-size: 1.5em; margin-top: 2em; }
    h3 { color: #444; font-size: 1.2em; }
    pre { background: #f4f4f4; border-left: 4px solid #0070f3; padding: 16px; overflow-x: auto; border-radius: 4px; }
    code { background: #f0f0f0; padding: 2px 6px; border-radius: 3px; font-family: monospace; font-size: 0.9em; }
    pre code { background: none; padding: 0; }
    .meta { background: #f9f9f9; border: 1px solid #eee; padding: 12px 20px; border-radius: 6px; margin-bottom: 24px; }
    .footer { margin-top: 40px; padding-top: 20px; border-top: 1px solid #eee; color: #888; font-size: 0.85em; }
  </style>
</head>
<body>
  <div class="meta">
    <strong>Topic:</strong> ${topicText}<br>
    <strong>Generated:</strong> ${new Date().toISOString()}<br>
    <strong>Topic ID:</strong> ${topicId}
  </div>
  <p>${htmlContent}</p>
  <div class="footer">
    <p>Generated by n8n Article Automation · <a href="https://n8n.yourdomain.com">View in n8n</a></p>
  </div>
</body>
</html>
`;

return [{
  json: {
    topicId,
    topicText,
    articleTitle,
    articleContent,
    emailHtml,
    wordCount: articleContent.split(/\s+/).length,
    generatedAt: new Date().toISOString()
  }
}];
